
class EndpointSubset {final List<EndpointAddress>? addresses; final List<EndpointAddress>? notReadyAddresses; final List<EndpointPort>? ports; EndpointSubset({this.addresses, this.notReadyAddresses, this.ports}); factory EndpointSubset.fromJson(Map<String, dynamic> json) {return EndpointSubset(addresses: json['addresses'] != null ? (json['addresses'] as List).map((e) => EndpointAddress.fromJson(e)).toList() : null, notReadyAddresses: json['notReadyAddresses'] != null ? (json['notReadyAddresses'] as List).map((e) => EndpointAddress.fromJson(e)).toList() : null, ports: json['ports'] != null ? (json['ports'] as List).map((e) => EndpointPort.fromJson(e)).toList() : null);} Map<String, dynamic> toJson() {return {if (addresses != null) 'addresses' : addresses!.map((e) => e.toJson()).toList(), if (notReadyAddresses != null) 'notReadyAddresses' : notReadyAddresses!.map((e) => e.toJson()).toList(), if (ports != null) 'ports' : ports!.map((e) => e.toJson()).toList()};}}
